module RefModule(IN_FLAG,
    LD,
    SET,
    CLR,
    CLK,
    OUT_FLAG);input IN_FLAG;
  input LD;
  input SET;
  input CLR;
  input CLK;
  output OUT_FLAG;

  reg unused_flag;

  always @(posedge CLK) begin
    if (LD) begin
      unused_flag <= IN_FLAG;
    end else if (SET) begin
      unused_flag <= 1;
    end else if (CLR) begin
      unused_flag <= 0;
    end
  end

  assign OUT_FLAG = unused_flag;

endmodule
